def seed_standard_mitarbeiter(db):
    # Nur INSERT, nie UPDATE: spaetere Aenderungen/Loeschungen im Admin bleiben
    # erhalten. Legt die Stamm-Belegschaft an, falls noch nicht vorhanden
    # (Namensabgleich case-insensitive), damit die Werkstatt-Abwesenheits- und
    # Aufgabenauswahl sofort befuellt ist.
    now = now_str()
    for person in STANDARD_MITARBEITER:
        existing = db.execute(
            "SELECT id FROM mitarbeiter WHERE LOWER(TRIM(name))=LOWER(TRIM(?))",
            (person["name"],),
        ).fetchone()
        if existing:
            continue
        db.execute(
            """
            INSERT INTO mitarbeiter (name, rolle, aktiv, erstellt_am, geaendert_am)
            VALUES (?, ?, 1, ?, ?)
            """,
            (person["name"], person["rolle"], now, now),
        )


def seed_default_autohaeuser(db):
    now = now_str()
    for autohaus in DEFAULT_AUTOHAEUSER:
        existing = db.execute(
            "SELECT id FROM autohaeuser WHERE slug=? OR portal_key=?",
            (autohaus["slug"], autohaus["portal_key"]),
        ).fetchone()
        stammdaten = (
            autohaus["name"],
            autohaus["slug"],
            autohaus["portal_key"],
            autohaus["kontakt_name"],
            autohaus["email"],
            autohaus["telefon"],
            autohaus["strasse"],
            autohaus["plz"],
            autohaus["ort"],
            autohaus["portal_titel"],
            autohaus["willkommen_text"],
            clean_text(autohaus.get("notiz")),
        )
        if existing:
            # Zugangscode bewusst NICHT anfassen: sonst setzt jeder Neustart
            # einen im Admin geaenderten/rotierten Code wieder zurueck.
            db.execute(
                """
                UPDATE autohaeuser
                SET name=?, slug=?, portal_key=?, kontakt_name=?, email=?, telefon=?,
                    strasse=?, plz=?, ort=?, portal_titel=?,
                    willkommen_text=?, notiz=?
                WHERE id=?
                """,
                stammdaten + (existing["id"],),
            )
            continue
        zugangscode = clean_text(autohaus.get("zugangscode")) or secrets.token_urlsafe(9)
        db.execute(
            """
            INSERT INTO autohaeuser
            (name, slug, portal_key, kontakt_name, email, telefon, strasse, plz, ort,
             zugangscode, portal_titel, willkommen_text, notiz, erstellt_am)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            stammdaten[:9] + (zugangscode,) + stammdaten[9:] + (now,),
        )


def seed_default_versicherungen(db):
    now = now_str()
    for versicherung in DEFAULT_VERSICHERUNGEN:
        existing = db.execute(
            "SELECT id, email FROM versicherungen WHERE slug=? OR portal_key=?",
            (versicherung["slug"], versicherung["portal_key"]),
        ).fetchone()
        values = (
            versicherung["name"],
            versicherung["slug"],
            versicherung["portal_key"],
            clean_text(versicherung.get("kontakt_name")),
            clean_text(versicherung.get("email")),
            clean_text(versicherung.get("telefon")),
            clean_text(versicherung.get("zugangscode")) or secrets.token_urlsafe(9),
            clean_text(versicherung.get("notiz")),
        )
        if existing:
            email_default = clean_text(versicherung.get("email"))
            email_current = clean_text(existing["email"]).lower()
            eigene_altvorschlaege = {
                "schaden@ergo.de",
                "info@auto-lackierzentrum.de",
                "info@hdi.de",
                "info@lvm.de",
            }
            email_update_value = email_default if not email_current else email_current
            if email_current in eigene_altvorschlaege and email_current != email_default.lower():
                email_update_value = email_default
            db.execute(
                """
                UPDATE versicherungen
                SET kontakt_name=CASE WHEN COALESCE(kontakt_name, '')='' THEN ? ELSE kontakt_name END,
                    email=CASE WHEN COALESCE(email, '')='' OR LOWER(COALESCE(email, '')) IN ('schaden@axa.de', 'schaden@ergo.de', 'info@hdi.de', 'info@lvm.de') THEN ? ELSE email END,
                    telefon=CASE WHEN COALESCE(telefon, '')='' THEN ? ELSE telefon END,
                    notiz=CASE WHEN COALESCE(notiz, '')='' THEN ? ELSE notiz END
                WHERE id=?
                """,
                (
                    clean_text(versicherung.get("kontakt_name")),
                    email_update_value,
                    clean_text(versicherung.get("telefon")),
                    clean_text(versicherung.get("notiz")),
                    existing["id"],
                ),
            )
            continue
        db.execute(
            """
            INSERT INTO versicherungen
              (name, slug, portal_key, kontakt_name, email, telefon, zugangscode, notiz, erstellt_am)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            values + (now,),
        )


