def iter_gt_dicts(value):
    if isinstance(value, dict):
        yield value
        for child in value.values():
            yield from iter_gt_dicts(child)
    elif isinstance(value, list):
        for child in value:
            yield from iter_gt_dicts(child)


def gt_motive_payload_summary(payload):
    labels = []
    amount = ""
    model_code = ""
    for node in iter_gt_dicts(payload):
        if not amount:
            for key, value in node.items():
                key_norm = str(key).lower()
                if any(word in key_norm for word in ("amount", "betrag", "total", "cost", "price", "kalkulation")):
                    candidate = clean_text(value)
                    if candidate and re.search(r"\d", candidate):
                        amount = candidate[:80]
                        break
        if not model_code:
            for key, value in node.items():
                if str(key).lower().replace("_", "") in {"modelcode", "umc", "modelid"}:
                    candidate = clean_text(value).upper()
                    if candidate:
                        model_code = candidate[:80]
                        break
        for key in ("description", "name", "pieceDescription", "partDescription", "label"):
            label = clean_text(gt_payload_value(node, key))
            if label and len(label) >= 3 and label not in labels:
                labels.append(label[:120])
            if len(labels) >= 12:
                break
    return {
        "amount": amount,
        "model_code": model_code,
        "labels": labels[:12],
    }


def update_gt_motive_vehicle_representation_result(auftrag_id, payload=None, error=""):
    payload_text = json.dumps(payload, ensure_ascii=False) if payload is not None else ""
    summary = gt_motive_payload_summary(payload) if payload is not None else {}
    amount = clean_text(summary.get("amount"))
    model_code = clean_text(summary.get("model_code")).upper()
    labels = [clean_text(label) for label in summary.get("labels", []) if clean_text(label)]
    db = get_db()
    db.execute(
        """
        UPDATE auftraege
        SET gt_motive_vehicle_representation_json=?,
            gt_motive_vehicle_representation_loaded_at=?,
            gt_motive_vehicle_representation_error=?,
            gt_motive_status=?,
            gt_motive_kalkulation_betrag=CASE WHEN ? != '' THEN ? ELSE gt_motive_kalkulation_betrag END,
            gt_motive_model_code=CASE WHEN ? != '' AND COALESCE(gt_motive_model_code, '')='' THEN ? ELSE gt_motive_model_code END,
            bauteile_override=CASE WHEN ? != '' AND COALESCE(bauteile_override, '')='' THEN ? ELSE bauteile_override END,
            geaendert_am=?
        WHERE id=?
        """,
        (
            payload_text,
            now_str() if payload is not None else "",
            clean_text(error)[:1000],
            "fahrzeugdarstellung_geladen" if payload is not None else "api_fehler",
            amount,
            amount,
            model_code,
            model_code,
            "\n".join(labels),
            "\n".join(labels),
            now_str(),
            auftrag_id,
        ),
    )
    db.commit()
    db.close()


def fetch_gt_motive_vehicle_representation(config):
    requests_module = get_requests()
    if requests_module is None:
        raise RuntimeError("Python-Modul requests fehlt. Bitte requirements installieren.")
    if not gt_motive_is_configured():
        raise RuntimeError("GT_MOTIVE_API_KEY oder GT_MOTIVE_CLIENT_ID fehlt in .env.local.")
    model_code = clean_text(config.get("model_code")).upper()
    zone = clean_text(config.get("zone"))
    if not model_code:
        raise ValueError("GT Modellcode (UMC) fehlt, z.B. CI02301.")
    if not zone:
        raise ValueError("GT-Modellzone fehlt, z.B. 11000.")
    url = f"{GT_MOTIVE_API_BASE_URL}/api/models/{quote(model_code, safe='')}/zones/{quote(zone, safe='')}/vehiclerepresentation"
    params = {}
    for api_key, local_key in (
        ("jobType", "job_type"),
        ("equipments", "equipments"),
        ("manufacturingValues", "manufacturing_values"),
        ("language", "language"),
        ("modelId", "model_id"),
    ):
        value = clean_text(config.get(local_key))
        if value:
            params[api_key] = value
    response = requests_module.get(
        url,
        headers=gt_motive_headers(),
        params=params,
        timeout=GT_MOTIVE_TIMEOUT_SECONDS,
    )
    if response.status_code >= 400:
        detail = clean_text(response.text)[:500]
        raise RuntimeError(f"GT API antwortet mit HTTP {response.status_code}. {detail}")
    try:
        return response.json()
    except ValueError:
        text_payload = clean_text(response.text)
        if text_payload:
            return {"raw": text_payload}
        return {}


def sanitize_gt_svg(svg_text):
    svg_text = clean_text(svg_text)
    if not svg_text or "<svg" not in svg_text.lower():
        return ""
    svg_text = re.sub(r"<\s*(script|foreignObject)\b.*?<\s*/\s*\1\s*>", "", svg_text, flags=re.IGNORECASE | re.DOTALL)
    svg_text = re.sub(r"\s+on[a-zA-Z]+\s*=\s*(['\"]).*?\1", "", svg_text, flags=re.IGNORECASE | re.DOTALL)
    svg_text = re.sub(r"\s+(href|xlink:href)\s*=\s*(['\"])\s*(javascript:|data:text/html).*?\2", "", svg_text, flags=re.IGNORECASE | re.DOTALL)
    return svg_text


def gt_payload_value(source, *names, default=""):
    if not isinstance(source, dict):
        return default
    wanted = {name.lower().replace("_", "") for name in names}
    for key, value in source.items():
        normalized = str(key).lower().replace("_", "")
        if normalized in wanted:
            return value
    return default


def gt_float(value, default=0.0):
    try:
        return float(str(value).replace(",", "."))
    except (TypeError, ValueError):
        return default


def gt_find_svg_string(value):
    if isinstance(value, str):
        return value if "<svg" in value.lower() else ""
    if isinstance(value, dict):
        for key in ("svg", "svgImage", "svg_image", "image", "data", "content"):
            candidate = gt_payload_value(value, key)
            if isinstance(candidate, str) and "<svg" in candidate.lower():
                return candidate
    return ""


def iter_gt_svg_nodes(value):
    svg = gt_find_svg_string(value)
    if svg:
        yield value if isinstance(value, dict) else {"svg": svg}
        return
    if isinstance(value, dict):
        for child in value.values():
            yield from iter_gt_svg_nodes(child)
    elif isinstance(value, list):
        for child in value:
            yield from iter_gt_svg_nodes(child)


def gt_motive_vehicle_representation_items(auftrag):
    raw = clean_text((auftrag or {}).get("gt_motive_vehicle_representation_json"))
    if not raw:
        return []
    try:
        payload = json.loads(raw)
    except Exception:
        return []
    items = []
    for index, node in enumerate(iter_gt_svg_nodes(payload)):
        svg = sanitize_gt_svg(gt_find_svg_string(node))
        if not svg:
            continue
        x = gt_float(gt_payload_value(node, "x", "posX", "positionX", default=0))
        y = gt_float(gt_payload_value(node, "y", "posY", "positionY", default=0))
        scale = gt_float(gt_payload_value(node, "scale", "scaling", "zoom", default=1), 1.0)
        rotation = gt_float(gt_payload_value(node, "rotation", "rotate", "angle", default=0))
        order = int(gt_float(gt_payload_value(node, "order", "z", "zIndex", "stackOrder", default=index), index))
        label = clean_text(
            gt_payload_value(node, "description", "name", "pieceDescription", "partDescription", default="")
        )
        items.append(
            {
                "svg": svg,
                "x": x,
                "y": y,
                "scale": max(scale, 0.01),
                "rotation": rotation,
                "order": order,
                "label": label,
            }
        )
    return sorted(items, key=lambda item: item["order"])


def lackierauftrag_default_data(autohaus):
    telefon_email = " / ".join(
        part
        for part in (clean_text(autohaus.get("telefon")), clean_text(autohaus.get("email")))
        if part
    )
    data = {
        "firma": clean_text(autohaus.get("name")),
        "ansprechpartner": clean_text(autohaus.get("kontakt_name")),
        "kontakt": telefon_email,
        "auftrags_datum": date.today().strftime(DATE_FMT),
        "fertig_bis": "",
        "typ": "",
        "kennzeichen": "",
        "fg_nr": "",
        "farb_nr": "",
        "km_stand": "",
        "abrechnung": "",
        "versicherung_schaden_nr": "",
        "versicherungsnehmer": "",
        "kontrolle_datum": "",
        "unterschrift_auftragnehmer": "",
    }
    for index in range(1, LACKIERAUFTRAG_POSITION_COUNT + 1):
        data[f"position_{index}_teil"] = ""
        data[f"position_{index}_seite"] = ""
        data[f"position_{index}_bemerkung"] = ""
        data[f"position_{index}_status"] = ""
    return data


def normalize_lackierauftrag_data(raw_data, autohaus=None):
    data = lackierauftrag_default_data(autohaus or {})
    for key in list(data.keys()):
        data[key] = clean_text((raw_data or {}).get(key, data[key]))[:600]
    abrechnung = clean_text((raw_data or {}).get("abrechnung"))
    allowed_abrechnung = {key for key, _ in LACKIERAUFTRAG_ABRECHNUNG}
    data["abrechnung"] = abrechnung if abrechnung in allowed_abrechnung else ""
    for date_key in ("auftrags_datum", "fertig_bis", "kontrolle_datum"):
        data[date_key] = format_date(data.get(date_key)) or clean_text(data.get(date_key))
    return data


def parse_lackierauftrag_form(form, autohaus):
    return normalize_lackierauftrag_data(form, autohaus)


def get_lackierauftrag_entwurf(autohaus):
    defaults = lackierauftrag_default_data(autohaus)
    db = get_db()
    row = db.execute(
        """
        SELECT *
        FROM lackierauftrag_entwuerfe
        WHERE autohaus_id=?
        ORDER BY id DESC
        LIMIT 1
        """,
        (autohaus["id"],),
    ).fetchone()
    db.close()
    if not row:
        return {
            "id": 0,
            "daten": defaults,
            "erstellt_am": "",
            "geaendert_am": "",
        }
    try:
        saved = json.loads(row["daten_json"] or "{}")
    except Exception:
        saved = {}
    merged = dict(defaults)
    merged.update(saved if isinstance(saved, dict) else {})
    return {
        "id": row["id"],
        "daten": normalize_lackierauftrag_data(merged, autohaus),
        "erstellt_am": clean_text(row["erstellt_am"]),
        "geaendert_am": clean_text(row["geaendert_am"]),
    }


def save_lackierauftrag_entwurf(autohaus, data):
    normalized = normalize_lackierauftrag_data(data, autohaus)
    payload = json.dumps(normalized, ensure_ascii=False)
    now = now_str()
    db = get_db()
    existing = db.execute(
        "SELECT id FROM lackierauftrag_entwuerfe WHERE autohaus_id=? ORDER BY id DESC LIMIT 1",
        (autohaus["id"],),
    ).fetchone()
    if existing:
        db.execute(
            """
            UPDATE lackierauftrag_entwuerfe
            SET daten_json=?, geaendert_am=?
            WHERE id=?
            """,
            (payload, now, existing["id"]),
        )
    else:
        db.execute(
            """
            INSERT INTO lackierauftrag_entwuerfe
            (autohaus_id, daten_json, erstellt_am, geaendert_am)
            VALUES (?, ?, ?, ?)
            """,
            (autohaus["id"], payload, now, now),
        )
    db.commit()
    db.close()
    return normalized


def lackierauftrag_beschreibung_aus_positionen(daten):
    zeilen = []
    for index in range(1, LACKIERAUFTRAG_POSITION_COUNT + 1):
        teil = clean_text((daten or {}).get(f"position_{index}_teil"))
        if not teil:
            continue
        seite = clean_text((daten or {}).get(f"position_{index}_seite"))
        bemerkung = clean_text((daten or {}).get(f"position_{index}_bemerkung"))
        status = clean_text((daten or {}).get(f"position_{index}_status"))
        teil_text = f"{teil} ({seite})" if seite else teil
        rest = " – ".join(part for part in (bemerkung, status) if part)
        zeilen.append(f"{teil_text}: {rest}" if rest else teil_text)
    return "\n".join(zeilen)


def create_auftrag_aus_lackierauftrag(autohaus, daten):
    beschreibung = lackierauftrag_beschreibung_aus_positionen(daten)
    return create_auftrag(
        "autohaus",
        autohaus_id=autohaus["id"],
        kunde_name=clean_text((daten or {}).get("versicherungsnehmer")),
        fahrzeug=clean_text((daten or {}).get("typ")),
        fin_nummer=normalize_fin((daten or {}).get("fg_nr")),
        kilometerstand=clean_text((daten or {}).get("km_stand")),
        kennzeichen=clean_text((daten or {}).get("kennzeichen")).upper(),
        schaden_nummer=clean_text((daten or {}).get("versicherung_schaden_nr")),
        beschreibung=beschreibung,
        analyse=analyse_text(beschreibung),
        annahme_datum=clean_text((daten or {}).get("auftrags_datum")),
        fertig_datum=clean_text((daten or {}).get("fertig_bis")),
        kontakt_telefon=clean_text((daten or {}).get("kontakt")),
        transport_art="standard",
        notiz_intern="Aus Online-Lackierauftrag übernommen.",
    )


def lackierauftrag_filename(autohaus):
    slug = clean_text(autohaus.get("slug")) or slugify(autohaus.get("name")) or "autohaus"
    return f"Lackierauftrag_{slug}.pdf"


