def get_unique_slug(name):
    base_slug = slugify(name)
    db = get_db()
    slug = base_slug
    counter = 2
    while db.execute("SELECT 1 FROM autohaeuser WHERE slug=?", (slug,)).fetchone():
        slug = f"{base_slug}-{counter}"
        counter += 1
    db.close()
    return slug


