def hydrate_fahrzeugverkauf_datei(row):
    item = dict(row or {})
    item["original_name"] = clean_text(item.get("original_name"))
    item["stored_name"] = clean_text(item.get("stored_name"))
    item["mime_type"] = clean_text(item.get("mime_type")) or "application/octet-stream"
    item["kategorie"] = clean_text(item.get("kategorie")) or "unterlage"
    item["quelle"] = clean_text(item.get("quelle")) or "intern"
    item["extrahierter_text"] = clean_text(item.get("extrahierter_text"))
    item["extrakt_kurz"] = clean_text(item.get("extrakt_kurz"))
    item["analyse_quelle"] = clean_text(item.get("analyse_quelle"))
    item["analyse_hinweis"] = clean_text(item.get("analyse_hinweis"))
    item["hochgeladen_am"] = clean_text(item.get("hochgeladen_am"))
    suffix = pathlib.Path(item["original_name"]).suffix.lower()
    item["is_pdf"] = suffix == ".pdf"
    item["is_image"] = suffix in IMAGE_EXTENSIONS
    item["is_browser_image"] = suffix in {".jpg", ".jpeg", ".png", ".webp", ".gif"}
    item["url"] = url_for("admin_fahrzeugverkauf_datei", datei_id=item["id"]) if item.get("id") else ""
    return item


def list_fahrzeugverkauf_dateien(verkauf_id, kategorie=""):
    db = get_db()
    if clean_text(kategorie):
        rows = db.execute(
            """
            SELECT *
            FROM fahrzeugverkauf_dateien
            WHERE verkauf_id=? AND kategorie=?
            ORDER BY id DESC
            """,
            (int(verkauf_id), clean_text(kategorie)),
        ).fetchall()
    else:
        rows = db.execute(
            """
            SELECT *
            FROM fahrzeugverkauf_dateien
            WHERE verkauf_id=?
            ORDER BY id DESC
            """,
            (int(verkauf_id),),
        ).fetchall()
    db.close()
    return [hydrate_fahrzeugverkauf_datei(row) for row in rows]


def list_fahrzeugverkauf_dateien_for_verkaeufe(verkauf_ids):
    ids = [int(verkauf_id) for verkauf_id in verkauf_ids if verkauf_id]
    if not ids:
        return {}
    placeholders = ",".join("?" for _ in ids)
    db = get_db()
    rows = db.execute(
        f"""
        SELECT *
        FROM fahrzeugverkauf_dateien
        WHERE verkauf_id IN ({placeholders})
        ORDER BY id DESC
        """,
        ids,
    ).fetchall()
    db.close()
    grouped = {verkauf_id: [] for verkauf_id in ids}
    for row in rows:
        datei = hydrate_fahrzeugverkauf_datei(row)
        grouped.setdefault(int(datei["verkauf_id"]), []).append(datei)
    return grouped


def get_fahrzeugverkauf_datei(datei_id):
    db = get_db()
    row = db.execute("SELECT * FROM fahrzeugverkauf_dateien WHERE id=?", (int(datei_id),)).fetchone()
    db.close()
    return hydrate_fahrzeugverkauf_datei(row) if row else None


def get_fahrzeugverkauf_bild(verkauf, dateien):
    selected_id = int((verkauf or {}).get("verkauf_bild_datei_id") or 0)
    bilder = [datei for datei in (dateien or []) if datei.get("is_browser_image") and datei.get("kategorie") == "bild"]
    if selected_id:
        for bild in bilder:
            if int(bild.get("id") or 0) == selected_id:
                return bild
    return bilder[0] if bilder else None


def save_fahrzeugverkauf_uploads(verkauf_id, files, kategorie="unterlage", analyze=True):
    saved = 0
    errors = []
    extracted_items = []
    kategorie = clean_text(kategorie) or "unterlage"
    timestamp = now_str()
    analysis_deadline = document_analysis_deadline()
    db = get_db()
    try:
        UPLOAD_DIR.mkdir(parents=True, exist_ok=True)
    except Exception as exc:
        db.close()
        return 0, [], f"Upload-Speicher ist nicht erreichbar: {clean_text(str(exc))[:300]}"
    for file in files or []:
        if not file or not file.filename:
            continue
        original_name = secure_filename(file.filename or "")
        if not original_name or not allowed_file(original_name):
            continue
        suffix = pathlib.Path(original_name).suffix.lower()
        stored_name = f"{uuid.uuid4().hex}{suffix}"
        target = UPLOAD_DIR / stored_name
        try:
            file.save(target)
        except Exception as exc:
            errors.append(f"{original_name} konnte nicht gespeichert werden: {clean_text(str(exc))[:180]}")
            continue
        mime_type = file.mimetype or mimetypes.guess_type(original_name)[0] or "application/octet-stream"
        extracted_text = ""
        summary = ""
        analysis_source = ""
        analysis_hint = ""
        analysis_json = ""
        if analyze and kategorie == "unterlage" and suffix in ANALYSIS_EXTENSIONS:
            if document_analysis_time_available(analysis_deadline):
                bundle = build_document_analysis_bundle_safe(target, original_name)
                extracted_text = clean_text(bundle.get("text"))
                analysis_source = clean_text(bundle.get("source"))
                analysis_hint = clean_text(bundle.get("hint"))
                analysis_json = clean_text(bundle.get("analysis_json"))
                summary = structured_analysis_summary(bundle.get("structured"), original_name) or summarize_document_text(extracted_text, original_name)
                extracted_items.extend(verkauf_ausstattung_from_text(extracted_text))
            else:
                analysis_source = "analysis_timeout"
                analysis_hint = document_analysis_timeout_hint()
                errors.append(f"{original_name}: {analysis_hint}")
        cursor = db.execute(
            """
            INSERT INTO fahrzeugverkauf_dateien
            (verkauf_id, original_name, stored_name, mime_type, size, kategorie, quelle,
             extrahierter_text, extrakt_kurz, analyse_quelle, analyse_hinweis, analyse_json, hochgeladen_am)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                int(verkauf_id),
                original_name,
                stored_name,
                mime_type,
                target.stat().st_size,
                kategorie,
                "intern",
                extracted_text,
                summary,
                analysis_source,
                analysis_hint,
                analysis_json,
                timestamp,
            ),
        )
        if kategorie == "bild":
            db.execute(
                "UPDATE fahrzeugverkaeufe SET bild_datei_id=CASE WHEN COALESCE(bild_datei_id, 0)=0 THEN ? ELSE bild_datei_id END WHERE id=?",
                (int(cursor.lastrowid), int(verkauf_id)),
            )
        saved += 1
    db.execute("UPDATE fahrzeugverkaeufe SET geaendert_am=? WHERE id=?", (now_str(), int(verkauf_id)))
    db.commit()
    db.close()
    return saved, extracted_items, (errors[0] if errors else "")


def apply_verkaufsunterlagen_to_fahrzeugverkauf(verkauf_id, existing_text=""):
    result = apply_verkaufsdokumente_to_fahrzeugverkauf(verkauf_id)
    return result.get("equipment") or []


def list_fahrzeugverkaeufe(status_filter="aktiv"):
    db = get_db()
    rows = db.execute(
        """
        SELECT *
        FROM fahrzeugverkaeufe
        ORDER BY geaendert_am DESC, id DESC
        """
    ).fetchall()
    db.close()
    items = [hydrate_fahrzeugverkauf(row) for row in rows]
    if status_filter == "aktiv":
        items = [item for item in items if item.get("verkauf_status") != "verkauft"]
    elif status_filter == "verkauft":
        items = [item for item in items if item.get("verkauf_status") == "verkauft"]
    elif status_filter in VERKAUF_STATUS:
        items = [item for item in items if item.get("verkauf_status") == status_filter]
    dateien_by_verkauf = list_fahrzeugverkauf_dateien_for_verkaeufe([item["id"] for item in items])
    for item in items:
        dateien = dateien_by_verkauf.get(int(item["id"]), [])
        item["verkauf_bild"] = get_fahrzeugverkauf_bild(item, dateien)
        item["verkaufsunterlagen_count"] = len([datei for datei in dateien if datei.get("kategorie") == "unterlage"])
    return items


def list_angebotsanfragen(autohaus_id=None):
    db = get_db()
    if autohaus_id is None:
        rows = db.execute(
            """
            SELECT a.*, h.name AS autohaus_name, h.slug AS autohaus_slug,
                   (
                       SELECT COUNT(*)
                       FROM dateien d
                       WHERE d.auftrag_id = a.id
                   ) AS dateien_count
            FROM auftraege a
            LEFT JOIN autohaeuser h ON h.id = a.autohaus_id
            WHERE a.angebotsphase = 1 AND a.angebot_abgesendet = 1
            ORDER BY a.geaendert_am DESC, a.id DESC
            """
        ).fetchall()
    else:
        rows = db.execute(
            """
            SELECT a.*, h.name AS autohaus_name, h.slug AS autohaus_slug,
                   (
                       SELECT COUNT(*)
                       FROM dateien d
                       WHERE d.auftrag_id = a.id
                   ) AS dateien_count
            FROM auftraege a
            LEFT JOIN autohaeuser h ON h.id = a.autohaus_id
            WHERE a.angebotsphase = 1 AND a.angebot_abgesendet = 1 AND a.autohaus_id = ?
            ORDER BY a.geaendert_am DESC, a.id DESC
            """,
            (autohaus_id,),
        ).fetchall()
    db.close()
    anfragen = [row_to_auftrag(row) for row in rows]
    dateien_by_auftrag = list_dateien_for_auftraege([anfrage["id"] for anfrage in anfragen])
    for anfrage in anfragen:
        anfrage["dateien_count"] = int(anfrage.get("dateien_count") or 0)
        anfrage["dateien"] = dateien_by_auftrag.get(int(anfrage["id"]), [])
    return anfragen


def get_status_ids_logged_today(auftraege, status):
    ids = [int(a["id"]) for a in auftraege if a.get("status") == status]
    if not ids:
        return set()
    placeholders = ",".join("?" for _ in ids)
    heute_prefix = date.today().strftime(DATE_FMT) + "%"
    db = get_db()
    rows = db.execute(
        f"""
        SELECT DISTINCT auftrag_id
        FROM status_log
        WHERE status=?
          AND zeitstempel LIKE ?
          AND auftrag_id IN ({placeholders})
        """,
        (status, heute_prefix, *ids),
    ).fetchall()
    db.close()
    return {int(row["auftrag_id"]) for row in rows}


def is_today_finished_auftrag(auftrag, today_finished_ids, today):
    return (
        auftrag["status"] == 4
        and (
            auftrag["fertig_datum_obj"] == today
            or int(auftrag["id"]) in today_finished_ids
        )
    )


def list_dateien(auftrag_id):
    db = get_db()
    rows = db.execute(
        "SELECT * FROM dateien WHERE auftrag_id=? ORDER BY hochgeladen_am DESC, id DESC",
        (auftrag_id,),
    ).fetchall()
    db.close()
    return [hydrate_datei(dict(row)) for row in rows]


def list_dateien_for_auftraege(auftrag_ids):
    ids = [int(auftrag_id) for auftrag_id in auftrag_ids if auftrag_id]
    if not ids:
        return {}
    placeholders = ",".join("?" for _ in ids)
    db = get_db()
    rows = db.execute(
        f"""
        SELECT *
        FROM dateien
        WHERE auftrag_id IN ({placeholders})
        ORDER BY hochgeladen_am DESC, id DESC
        """,
        ids,
    ).fetchall()
    db.close()
    grouped = {auftrag_id: [] for auftrag_id in ids}
    for row in rows:
        datei = hydrate_datei(dict(row))
        grouped.setdefault(int(datei["auftrag_id"]), []).append(datei)
    return grouped


def split_dateien(dateien):
    standard = [d for d in dateien if clean_text(d.get("kategorie")) != "fertigbild"]
    fertigbilder = [d for d in dateien if clean_text(d.get("kategorie")) == "fertigbild"]
    return standard, fertigbilder


def dateien_mit_kategorie(dateien, kategorie):
    return [d for d in dateien if clean_text(d.get("kategorie")) == kategorie]


def get_datei(datei_id):
    db = get_db()
    row = db.execute("SELECT * FROM dateien WHERE id=?", (datei_id,)).fetchone()
    db.close()
    return hydrate_datei(dict(row)) if row else None


def delete_partner_datei(autohaus_id, datei_id):
    datei = get_datei(datei_id)
    if not datei:
        return False, None
    auftrag = get_auftrag(datei["auftrag_id"])
    if (
        not auftrag
        or int(auftrag.get("autohaus_id") or 0) != int(autohaus_id or 0)
        or clean_text(datei.get("quelle")) != "autohaus"
    ):
        return False, None

    stored_name = pathlib.Path(clean_text(datei.get("stored_name"))).name
    path = UPLOAD_DIR / stored_name
    try:
        move_upload_to_deleted_area(path, f"partner-datei-{datei_id}")
    except OSError:
        pass

    db = get_db()
    delete_datei_backup(db, datei_id)
    db.execute("DELETE FROM dateien WHERE id=? AND auftrag_id=? AND quelle='autohaus'", (datei_id, auftrag["id"]))
    db.execute("UPDATE auftraege SET geaendert_am=? WHERE id=?", (now_str(), auftrag["id"]))
    db.commit()
    db.close()

    if clean_text(datei.get("notiz")):
        try:
            apply_document_data_to_auftrag(auftrag["id"], prefer_documents=False)
        except Exception:
            pass

    if clean_text(datei.get("kategorie")) == "standard":
        reset_document_review_checks(
            auftrag["id"],
            "Eine hochgeladene Unterlage wurde entfernt. Bitte die erkannten Daten kurz prüfen.",
        )
    return True, auftrag


def delete_admin_datei(datei_id):
    datei = get_datei(datei_id)
    if not datei:
        return False, None
    auftrag = get_auftrag(datei["auftrag_id"])
    if not auftrag:
        return False, None

    stored_name = pathlib.Path(clean_text(datei.get("stored_name"))).name
    path = UPLOAD_DIR / stored_name
    try:
        move_upload_to_deleted_area(path, f"admin-datei-{datei_id}")
    except OSError:
        pass

    db = get_db()
    delete_datei_backup(db, datei_id)
    db.execute("DELETE FROM dateien WHERE id=? AND auftrag_id=?", (datei_id, auftrag["id"]))
    db.execute("UPDATE auftraege SET geaendert_am=? WHERE id=?", (now_str(), auftrag["id"]))
    db.commit()
    db.close()

    if clean_text(datei.get("kategorie")) == "standard":
        reset_document_review_checks(
            auftrag["id"],
            "Eine Unterlage wurde entfernt. Bitte die erkannten Daten kurz prüfen.",
        )
    return True, auftrag


def hydrate_datei(datei):
    if not datei:
        return None

    suffix = pathlib.Path(datei["original_name"]).suffix.lower()
    datei["is_pdf"] = suffix == ".pdf"
    datei["is_image"] = suffix in IMAGE_EXTENSIONS
    datei["is_browser_image"] = suffix in {".jpg", ".jpeg", ".png", ".webp", ".gif"}
    datei["kategorie"] = clean_text(datei.get("kategorie")) or "standard"
    datei["prozess_key"] = clean_text(datei.get("prozess_key"))
    datei["kunde_sichtbar"] = int(datei.get("kunde_sichtbar") or 0)
    datei["notiz"] = clean_text(datei.get("notiz"))
    datei["has_analysis"] = bool(
        clean_text(datei.get("extrakt_kurz"))
        or clean_text(datei.get("extrahierter_text"))
        or clean_text(datei.get("analyse_json"))
        or clean_text(datei.get("analyse_quelle"))
    )
    datei["has_extract"] = bool(datei["has_analysis"] or clean_text(datei.get("notiz")))
    datei["text_preview"] = clean_text(datei.get("extrahierter_text"))[:2000]
    datei["original_available"] = upload_file_exists(datei)
    return datei


def upload_file_path(datei):
    stored_name = pathlib.Path(clean_text((datei or {}).get("stored_name"))).name
    if not stored_name:
        return None
    return UPLOAD_DIR / stored_name


def upload_backup_payload(path):
    try:
        data = path.read_bytes()
    except OSError:
        return "", "", 0
    if not data:
        return "", "", 0
    return base64.b64encode(data).decode("ascii"), hashlib.sha256(data).hexdigest(), len(data)


def store_datei_backup(db, datei_id, path):
    try:
        datei_id = int(datei_id or 0)
    except (TypeError, ValueError):
        return False
    if not datei_id:
        return False
    file_base64, file_sha256, size = upload_backup_payload(path)
    if not file_base64:
        return False
    db.execute("DELETE FROM datei_backups WHERE datei_id=?", (datei_id,))
    db.execute(
        """
        INSERT INTO datei_backups
        (datei_id, file_base64, file_sha256, size, erstellt_am)
        VALUES (?, ?, ?, ?, ?)
        """,
        (datei_id, file_base64, file_sha256, size, now_str()),
    )
    return True


def delete_datei_backup(db, datei_id):
    try:
        datei_id = int(datei_id or 0)
    except (TypeError, ValueError):
        return
    if datei_id:
        db.execute("DELETE FROM datei_backups WHERE datei_id=?", (datei_id,))


def backfill_existing_upload_backups(db):
    try:
        rows = db.execute(
            """
            SELECT d.id, d.stored_name
            FROM dateien d
            LEFT JOIN datei_backups b ON b.datei_id = d.id
            WHERE b.datei_id IS NULL
            ORDER BY d.id ASC
            """
        ).fetchall()
    except Exception:
        return 0
    created = 0
    for row in rows:
        stored_name = pathlib.Path(clean_text(row["stored_name"])).name
        if not stored_name:
            continue
        path = UPLOAD_DIR / stored_name
        if not path.exists() or not path.is_file():
            continue
        if store_datei_backup(db, row["id"], path):
            created += 1
    return created


def datei_backup_exists(datei_id):
    try:
        datei_id = int(datei_id or 0)
    except (TypeError, ValueError):
        return False
    if not datei_id:
        return False
    db = get_db()
    try:
        row = db.execute(
            "SELECT 1 FROM datei_backups WHERE datei_id=? LIMIT 1",
            (datei_id,),
        ).fetchone()
        return bool(row)
    finally:
        db.close()


def restore_upload_file_from_backup(datei, path):
    try:
        datei_id = int((datei or {}).get("id") or 0)
    except (TypeError, ValueError):
        return False
    if not datei_id or not path:
        return False
    db = get_db()
    try:
        row = db.execute(
            "SELECT file_base64, file_sha256 FROM datei_backups WHERE datei_id=?",
            (datei_id,),
        ).fetchone()
    finally:
        db.close()
    if not row:
        return False
    try:
        data = base64.b64decode(clean_text(row["file_base64"]), validate=True)
    except Exception:
        return False
    expected_hash = clean_text(row["file_sha256"]).lower()
    if expected_hash and hashlib.sha256(data).hexdigest().lower() != expected_hash:
        return False
    try:
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_bytes(data)
    except OSError:
        return False
    return True


def ensure_upload_file_available(datei):
    path = upload_file_path(datei)
    if not path:
        return None
    if path.exists() and path.is_file():
        return path
    if restore_upload_file_from_backup(datei, path):
        return path
    return None


def upload_file_exists(datei):
    path = upload_file_path(datei)
    if path and path.exists() and path.is_file():
        return True
    return datei_backup_exists((datei or {}).get("id"))


def missing_upload_response(datei, back_url=""):
    return (
        render_template_string(
            """
            <!doctype html>
            <html lang="de">
              <head>
                <meta charset="utf-8">
                <meta name="viewport" content="width=device-width, initial-scale=1">
                <title>Originaldatei fehlt</title>
                <style>
                  body { font-family: Arial, sans-serif; background: #f6f2ea; margin: 0; padding: 40px; color: #102033; }
                  .box { max-width: 820px; margin: 0 auto; background: #fffaf2; border: 1px solid #e2cda8; border-radius: 14px; padding: 28px; }
                  .name { font-weight: 700; margin: 12px 0; }
                  .hint { color: #6b5a36; line-height: 1.5; }
                  a { display: inline-block; margin-top: 18px; color: #102033; }
                </style>
              </head>
              <body>
                <div class="box">
                  <h1>Originaldatei nicht mehr verfügbar</h1>
                  <div class="name">{{ datei['original_name'] }}</div>
                  <p class="hint">
                    Die Auswertung ist noch im Auftrag gespeichert, aber die hochgeladene Originaldatei liegt
                    nicht mehr auf dem Server. Bitte die Datei erneut hochladen, damit sie wieder geöffnet oder
                    heruntergeladen werden kann.
                  </p>
                  {% if back_url %}<a href="{{ back_url }}">Zurück zum Auftrag</a>{% endif %}
                </div>
              </body>
            </html>
            """,
            datei=datei,
            back_url=back_url,
        ),
        404,
    )


def send_upload_file(datei, as_attachment=False, missing_back_url=""):
    path = ensure_upload_file_available(datei)
    if not path:
        return missing_upload_response(datei, missing_back_url)
    return send_file(
        path,
        download_name=datei["original_name"],
        mimetype=datei["mime_type"],
        as_attachment=as_attachment,
    )


def should_replace_fahrzeug(existing_value):
    existing = clean_text(existing_value).lower()
    return not existing or existing in {"fahrzeug", "neues fahrzeug", "unbekannt"}


def load_saved_analysis_json(value):
    raw = clean_text(value)
    if not raw:
        return {}
    try:
        data = json.loads(raw)
    except Exception:
        return {}
    try:
        return normalize_openai_document_data(data)
    except Exception:
        return {}


def looks_like_specific_work_text(value):
    normalized = normalize_document_text(value)
    if not normalized:
        return False
    return any(matches_any_pattern(patterns, normalized, normalized) for patterns in TEILE_PATTERNS.values())


def merge_document_fields(ai_fields, local_fields):
    fields = dict(ai_fields or {})
    review_notes = []
    previous_damage_parts = parse_manual_parts((local_fields or {}).get("_previous_damage_parts"))
    local_analysis = clean_text((local_fields or {}).get("analyse_text"))
    local_source = " ".join(
        clean_text((local_fields or {}).get(key))
        for key in ("beschreibung", "analyse_text", "bauteile_override")
    )
    if previous_damage_parts:
        cleaned_analysis = remove_previous_damage_fragments(
            fields.get("analyse_text"),
            previous_damage_parts,
            local_analysis,
        )
        cleaned_bauteile = remove_previous_damage_fragments(
            fields.get("bauteile_override"),
            previous_damage_parts,
            local_analysis,
        )
        if clean_text(fields.get("analyse_text")) and cleaned_analysis != clean_text(fields.get("analyse_text")):
            fields["analyse_text"] = cleaned_analysis
            review_notes.append("Vorschäden aus dem Gutachten wurden nicht als aktuelle Arbeit übernommen.")
        if clean_text(fields.get("bauteile_override")) and cleaned_bauteile != clean_text(fields.get("bauteile_override")):
            fields["bauteile_override"] = cleaned_bauteile
    for key, label, is_date in (
        ("fahrzeug", "Fahrzeugtyp", False),
        ("fin_nummer", "FIN", False),
        ("hsn_nummer", "HSN", False),
        ("tsn_nummer", "TSN", False),
        ("auftragsnummer", "Auftragsnummer", False),
        ("annahme_datum", "Auftrags-/Annahmedatum", True),
        ("fertig_datum", "Fertig-bis-Datum", True),
    ):
        ai_value = (ai_fields or {}).get(key)
        local_value = (local_fields or {}).get(key)
        if values_disagree(ai_value, local_value, is_date=is_date):
            review_notes.append(
                f"{label}: OCR und KI liefern unterschiedliche Werte. Bitte Originaldatei prüfen."
            )

    local_rep = clean_text((local_fields or {}).get("rep_max_kosten"))
    ai_rep = clean_text(fields.get("rep_max_kosten"))
    if ai_rep and local_source:
        sanitized_ai_rep = sanitize_reparaturkosten_value(ai_rep, local_source)
        if sanitized_ai_rep and not document_money_equal(ai_rep, sanitized_ai_rep):
            fields["rep_max_kosten"] = sanitized_ai_rep
            review_notes.append(
                "Reparaturkosten: WBW/Restwert wurde nicht als Reparaturkosten übernommen."
            )
        elif not sanitized_ai_rep and is_wert_money_value(ai_rep, local_source):
            fields["rep_max_kosten"] = ""
            review_notes.append(
                "Reparaturkosten: WBW/Restwert wurde nicht als Reparaturkosten übernommen."
            )
    if local_rep:
        current_rep = clean_text(fields.get("rep_max_kosten"))
        if current_rep and not document_money_equal(current_rep, local_rep):
            review_notes.append(
                "Reparaturkosten: OCR und KI liefern unterschiedliche Werte. Bitte Originaldatei prüfen."
            )
        fields["rep_max_kosten"] = local_rep

    for key, value in (local_fields or {}).items():
        if value and not clean_text(fields.get(key)):
            fields[key] = value

    ai_analysis = clean_text(fields.get("analyse_text"))
    if local_analysis and looks_like_specific_work_text(local_analysis):
        ai_is_generic = (
            not looks_like_specific_work_text(ai_analysis)
            or "durchgefuehrt" in normalize_document_text(ai_analysis)
        )
        if ai_is_generic:
            fields["analyse_text"] = local_analysis

    fields = quality_check_document_fields(fields)
    for note in review_notes:
        add_analysis_note(fields, note)
    return fields


def ensure_document_review_fallback(fields, extracted_text="", original_name=""):
    fields = dict(fields or {})
    if not clean_text(fields.get("analyse_text")):
        summary = summarize_document_text(extracted_text, original_name)
        if summary:
            fields["analyse_text"] = summary[:220]
    if not clean_text(fields.get("beschreibung")):
        doc_type = classify_document(extracted_text, original_name)
        parts = [part for part in (doc_type, summarize_document_text(extracted_text, original_name)) if clean_text(part)]
        if parts:
            fields["beschreibung"] = ". ".join(parts)[:500]
    if clean_text(fields.get("analyse_text")) or clean_text(fields.get("beschreibung")):
        add_analysis_note(
            fields,
            "Bitte überprüfen: Die Unterlage wurde automatisch eingetragen, aber die Erkennung ist unsicher.",
        )
    return fields


def normalized_review_value(key, value):
    value = clean_text(value)
    if not value:
        return ""
    if key in {"annahme_datum", "fertig_datum", "abholtermin", "start_datum"}:
        return format_date(value)
    if key == "rep_max_kosten":
        return normalize_document_money_value(value) or value
    if key == "hsn_nummer":
        return normalize_hsn(value)
    if key == "tsn_nummer":
        return normalize_tsn(value)
    if key in {"kennzeichen", "fin_nummer"}:
        return value.upper()
    return value


def values_match_for_review(key, left, right):
    left_value = normalized_review_value(key, left)
    right_value = normalized_review_value(key, right)
    if not left_value or not right_value:
        return False
    return left_value == right_value


def list_document_review_items(auftrag_id, auftrag=None):
    if not auftrag:
        auftrag = get_auftrag(auftrag_id)
    if not auftrag:
        return []

    db = get_db()
    rows = db.execute(
        """
        SELECT id, original_name, dokument_typ, notiz, extrahierter_text, analyse_json,
               analyse_quelle, analyse_hinweis
        FROM dateien
        WHERE auftrag_id=?
          AND kategorie='standard'
          AND reklamation_id IS NULL
          AND (extrahierter_text != '' OR analyse_json != '')
        ORDER BY id DESC
        """,
        (auftrag_id,),
    ).fetchall()
    db.close()

    reviews = []
    for row in rows:
        datei = dict(row)
        ai_felder = load_saved_analysis_json(datei.get("analyse_json"))
        review_text = append_upload_note_to_analysis(
            datei.get("extrahierter_text"),
            datei.get("notiz"),
        )
        local_felder = parse_document_fields(
            review_text,
            datei.get("original_name"),
        )
        felder = merge_document_fields(ai_felder, local_felder)
        items = []
        for key, label in DOCUMENT_REVIEW_FIELDS:
            value = normalized_review_value(key, felder.get(key))
            if not value:
                continue
            current_value = normalized_review_value(key, auftrag.get(key))
            items.append(
                {
                    "key": key,
                    "label": label,
                    "value": value,
                    "current_value": current_value,
                    "active": values_match_for_review(key, value, current_value),
                }
            )
        if items:
            reviews.append(
                {
                    "datei_id": datei["id"],
                    "original_name": clean_text(datei.get("original_name")),
                    "dokument_typ": clean_text(datei.get("dokument_typ")),
                    "analyse_quelle": clean_text(datei.get("analyse_quelle")),
                    "analyse_hinweis": clean_text(datei.get("analyse_hinweis"))
                    or clean_text(felder.get("analyse_hinweis")),
                    "needs_review": bool(felder.get("analyse_pruefen")),
                    "confidence": felder.get("analyse_confidence") or 0,
                    "items": items,
                }
            )
    return reviews


def reset_document_review_checks(auftrag_id, reason=""):
    hint = clean_text(reason) or "Neue Unterlage hochgeladen. Bitte erkannte Werte gegen die Originaldatei prüfen."
    db = get_db()
    db.execute(
        """
        UPDATE auftraege
        SET analyse_pruefen=1,
            analyse_hinweis=?,
            analyse_autohaus_geprueft=0,
            analyse_werkstatt_geprueft=0,
            analyse_geprueft_am='',
            geaendert_am=?
        WHERE id=?
        """,
        (hint, now_str(), auftrag_id),
    )
    db.commit()
    db.close()


def confirm_document_review(auftrag_id, role):
    if role not in {"autohaus", "werkstatt"}:
        return False
    auftrag = get_auftrag(auftrag_id)
    if not auftrag:
        return False
    autohaus_checked = 1 if role == "autohaus" else int(auftrag.get("analyse_autohaus_geprueft") or 0)
    werkstatt_checked = 1 if role == "werkstatt" else int(auftrag.get("analyse_werkstatt_geprueft") or 0)
    both_checked = bool(autohaus_checked and werkstatt_checked)
    hint = (
        "Dokumentdaten wurden von Autohaus und Werkstatt geprüft."
        if both_checked
        else "Dokumentdaten sind sichtbar. Bitte zweite Prüfung noch abschließen."
    )
    db = get_db()
    db.execute(
        """
        UPDATE auftraege
        SET analyse_autohaus_geprueft=?,
            analyse_werkstatt_geprueft=?,
            analyse_pruefen=?,
            analyse_hinweis=?,
            analyse_geprueft_am=?,
            geaendert_am=?
        WHERE id=?
        """,
        (
            autohaus_checked,
            werkstatt_checked,
            0 if both_checked else 1,
            hint,
            now_str() if both_checked else "",
            now_str(),
            auftrag_id,
        ),
    )
    db.commit()
    db.close()
    return both_checked


def apply_document_data_to_auftrag(auftrag_id, prefer_documents=False):
    db = get_db()
    auftrag_row = db.execute("SELECT * FROM auftraege WHERE id=?", (auftrag_id,)).fetchone()
    if not auftrag_row:
        db.close()
        return {}

    auftrag = dict(auftrag_row)
    analysis_double_checked = bool(
        int(auftrag.get("analyse_autohaus_geprueft") or 0)
        and int(auftrag.get("analyse_werkstatt_geprueft") or 0)
    )
    dateien = db.execute(
        """
        SELECT original_name, notiz, extrahierter_text, analyse_json, analyse_hinweis
        FROM dateien
        WHERE auftrag_id=? AND (extrahierter_text != '' OR analyse_json != '' OR notiz != '')
        ORDER BY id DESC
        """,
        (auftrag_id,),
    ).fetchall()

    erkannt = {}
    for datei in dateien:
        ai_felder = load_saved_analysis_json(datei["analyse_json"])
        review_text = append_upload_note_to_analysis(datei["extrahierter_text"], datei["notiz"])
        local_felder = parse_document_fields(review_text, datei["original_name"])
        felder = merge_document_fields(ai_felder, local_felder)
        felder = ensure_document_review_fallback(
            felder,
            review_text,
            datei["original_name"],
        )
        for key, value in felder.items():
            if key == "schaden_zonen_json" and clean_text(value):
                merged = merge_schaden_zonen(erkannt.get(key), value)
                if merged:
                    erkannt[key] = json.dumps(merged, ensure_ascii=False)
                continue
            if value and key not in erkannt:
                erkannt[key] = value

    updates = {}
    if erkannt.get("autohaus_id") and not auftrag.get("autohaus_id"):
        updates["autohaus_id"] = erkannt["autohaus_id"]
    if erkannt.get("fahrzeug") and (
        prefer_documents or should_replace_fahrzeug(auftrag.get("fahrzeug"))
    ):
        updates["fahrzeug"] = erkannt["fahrzeug"]
    if erkannt.get("fin_nummer") and (
        prefer_documents or not clean_text(auftrag.get("fin_nummer"))
    ):
        updates["fin_nummer"] = erkannt["fin_nummer"]
    if erkannt.get("hsn_nummer") and (
        prefer_documents or not clean_text(auftrag.get("hsn_nummer"))
    ):
        updates["hsn_nummer"] = normalize_hsn(erkannt["hsn_nummer"])
    if erkannt.get("tsn_nummer") and (
        prefer_documents or not clean_text(auftrag.get("tsn_nummer"))
    ):
        updates["tsn_nummer"] = normalize_tsn(erkannt["tsn_nummer"])
    if erkannt.get("auftragsnummer") and (
        prefer_documents or not clean_text(auftrag.get("auftragsnummer"))
    ):
        updates["auftragsnummer"] = erkannt["auftragsnummer"]
    if erkannt.get("rep_max_kosten") and (
        prefer_documents or not clean_text(auftrag.get("rep_max_kosten"))
    ):
        updates["rep_max_kosten"] = erkannt["rep_max_kosten"]
    if erkannt.get("bauteile_override") and (
        prefer_documents or not clean_text(auftrag.get("bauteile_override"))
    ):
        updates["bauteile_override"] = erkannt["bauteile_override"]
    if erkannt.get("schaden_zonen_json"):
        merged_zones = merge_schaden_zonen(
            auftrag.get("schaden_zonen_json"),
            erkannt.get("schaden_zonen_json"),
        )
        current_zones = parse_schaden_zonen(auftrag.get("schaden_zonen_json"))
        if merged_zones and (prefer_documents or merged_zones != current_zones):
            updates["schaden_zonen_json"] = json.dumps(merged_zones, ensure_ascii=False)
    if erkannt.get("kennzeichen") and (
        prefer_documents or not clean_text(auftrag.get("kennzeichen"))
    ):
        updates["kennzeichen"] = erkannt["kennzeichen"]
    if erkannt.get("annahme_datum") and (
        prefer_documents or not clean_text(auftrag.get("annahme_datum"))
    ):
        updates["annahme_datum"] = erkannt["annahme_datum"]
    if erkannt.get("fertig_datum") and (
        prefer_documents or not clean_text(auftrag.get("fertig_datum"))
    ):
        updates["fertig_datum"] = erkannt["fertig_datum"]
    if erkannt.get("fertig_datum") and (
        prefer_documents or not clean_text(auftrag.get("abholtermin"))
    ):
        updates["abholtermin"] = erkannt["fertig_datum"]
    if erkannt.get("analyse_text") and (
        prefer_documents
        or not clean_text(auftrag.get("analyse_text"))
        or len(clean_text(auftrag.get("analyse_text"))) < 10
    ):
        updates["analyse_text"] = erkannt["analyse_text"][:220]
    if erkannt.get("beschreibung") and (
        prefer_documents or not clean_text(auftrag.get("beschreibung"))
    ):
        updates["beschreibung"] = erkannt["beschreibung"]
    if "analyse_pruefen" in erkannt and not analysis_double_checked:
        updates["analyse_pruefen"] = 1 if erkannt.get("analyse_pruefen") else 0
    if erkannt.get("analyse_hinweis") and not analysis_double_checked:
        updates["analyse_hinweis"] = erkannt["analyse_hinweis"]
    if erkannt.get("analyse_confidence") is not None:
        updates["analyse_confidence"] = erkannt.get("analyse_confidence") or 0
    if updates:
        updates["geaendert_am"] = now_str()
        assignments = ", ".join(f"{feld}=?" for feld in updates)
        db.execute(
            f"UPDATE auftraege SET {assignments} WHERE id=?",
            tuple(updates.values()) + (auftrag_id,),
        )
        db.commit()

    db.close()
    return updates


