    try:
        db.execute(
            "UPDATE werkstatt_emails SET status=?, geaendert_am=? WHERE id=?",
            (status, now_str(), int(email_id)),
        )
        db.commit()
        schedule_change_backup("werkstatt-email-status")
    finally:
        db.close()


