        f"- Marke: {marke['label']}",
        f"- Fahrzeug: {fahrzeug}",
        f"- FIN: {fin}",
        f"- Kennzeichen: {kennzeichen}",
        f"- Schaden-Nr.: {schaden}",
        "",
